            flip(&mut result, curr_size - 1);
        }
    }

    result
}

fn flip(arr: &mut [i32], k: usize) {
    let mut i = 0;
    let mut j = k;
    while i < j {
        arr.swap(i, j);
        i += 1;
        j -= 1;
    }
}

